+            "Rolled back to v{} (backup {}).",
+            result.restored_version, result.snapshot_id
+        );
+        let _ = writeln!(out, "Restart the sbh service to use this version.");
+    } else if let Some(err) = &result.error {
+        let _ = writeln!(out, "Rollback failed: {err}");
+    }
+    out
+}
